const resp = $.steps.listDriveFiles.response || {};
const data = resp.data || resp;
const files = data.files || data.items || [];
const maxFiles = $.input.maxFiles || 5;
const limited = files.slice(0, maxFiles);
const fileList = limited.map(f => ({
  id: f.id || '',
  name: f.name || f.title || 'unknown',
  mimeType: f.mimeType || '',
  webViewLink: f.webViewLink || '',
  size: f.size || 0
}));
return { files: fileList, totalFound: files.length, processing: fileList.length };

const files = $.steps.parseFileList.output.files;
const goal = $.input.extractionGoal || 'Extract all text, tables, key data points, and structured information';

let prompt = 'You are a document and image analysis specialist. You have received metadata about files from Google Drive. For each file, provide a structured extraction analysis based on the file type and name.\n\n';
prompt += 'EXTRACTION GOAL: ' + goal + '\n';
prompt += 'FILES TO ANALYZE:\n';
files.forEach((f, i) => {
  prompt += (i + 1) + '. Name: ' + f.name + ' | Type: ' + f.mimeType + ' | Link: ' + f.webViewLink + '\n';
});
prompt += '\nFor each file, analyze the file name and type to infer what data it likely contains, and describe how to extract it. Provide a structured extraction plan.\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "summary": "overview of all files analyzed",\n';
prompt += '  "files": [\n';
prompt += '    {\n';
prompt += '      "fileName": "name",\n';
prompt += '      "fileType": "pdf/image/doc",\n';
prompt += '      "inferredContent": "what the file likely contains",\n';
prompt += '      "extractionPlan": "how to extract data from this type",\n';
prompt += '      "expectedDataPoints": ["field1", "field2"],\n';
prompt += '      "confidence": "high/medium/low"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "totalFiles": 0,\n';
prompt += '  "recommendations": ["suggestion for better extraction"]\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiExtract.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { summary: raw, files: [], totalFiles: 0, recommendations: [] }; }

const ai = $.steps.parseAI.output;
const stats = $.steps.parseFileList.output;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Document/Image Extraction Report', emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Files Found:*\n' + stats.totalFound },
  { type: 'mrkdwn', text: '*Files Processed:*\n' + stats.processing }
] });
blocks.push({ type: 'divider' });

const summaryText = (ai.summary || 'No summary available.').slice(0, 1800);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary:*\n' + summaryText } });

if (ai.files && ai.files.length > 0) {
  blocks.push({ type: 'divider' });
  ai.files.slice(0, 8).forEach((f, i) => {
    let text = '*' + (i + 1) + '. ' + (f.fileName || 'File') + '*';
    text += '\n:page_facing_up: Type: ' + (f.fileType || 'unknown');
    text += '\n:mag: ' + (f.inferredContent || 'N/A');
    if (f.expectedDataPoints && f.expectedDataPoints.length > 0) {
      text += '\n:pushpin: Fields: ' + f.expectedDataPoints.slice(0, 5).join(', ');
    }
    text += '\n:signal_strength: Confidence: ' + (f.confidence || 'N/A');
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text.slice(0, 1800) } });
  });
}

if (ai.recommendations && ai.recommendations.length > 0) {
  blocks.push({ type: 'divider' });
  let recText = '*Recommendations:*\n';
  ai.recommendations.slice(0, 3).forEach((r, i) => { recText += (i + 1) + '. ' + r + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: recText.slice(0, 1800) } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Google Drive + Claude AI + One CLI' }] });

const fallback = 'Doc Extraction: ' + stats.processing + ' files analyzed - ' + (ai.summary || '').slice(0, 100);
return { blocks, fallback };
